 {"id":"jeffreysprompts.com-19a6","title":"Add E2E visual regression tests for UI components","description":"# Task: E2E Visual Regression Tests

## Purpose
Capture baseline screenshots of all major UI components and detect visual regressions after changes. Critical for the color migration and UX changes.

## Testing Framework
Use Playwright's built-in screenshot comparison with Percy or custom implementation.

## Test Structure

### 1. Component Screenshot Tests
```typescript
// e2e/visual/components.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Component Visual Regression', () => {

  test.describe('PromptCard', () => {
    test('light mode - default state', async ({ page }) => {
      await page.goto('/');
      await page.waitForSelector('[data-testid="prompt-card"]');

      const card = page.locator('[data-testid="prompt-card"]').first();
      await expect(card).toHaveScreenshot('prompt-card-light-default.png', {
        maxDiffPixels: 100,
      });

      console.log('[VISUAL] PromptCard light mode default - captured');
    });

    test('light mode - hover state', async ({ page }) => {
      await page.goto('/');
      const card = page.locator('[data-testid="prompt-card"]').first();
      await card.hover();

      await expect(card).toHaveScreenshot('prompt-card-light-hover.png', {
        maxDiffPixels: 100,
      });

      console.log('[VISUAL] PromptCard light mode hover - captured');
    });

    test('dark mode - default state', async ({ page }) => {
      await page.goto('/');
      await page.evaluate(() => {
        document.documentElement.classList.add('dark');
      });

      const card = page.locator('[data-testid="prompt-card"]').first();
      await expect(card).toHaveScreenshot('prompt-card-dark-default.png', {
        maxDiffPixels: 100,
      });

      console.log('[VISUAL] PromptCard dark mode default - captured');
    });

    test('featured card variant', async ({ page }) => {
      await page.goto('/');
      const featuredCard = page.locator('[data-testid="prompt-card"][data-featured="true"]').first();

      if (await featuredCard.count() > 0) {
        await expect(featuredCard).toHaveScreenshot('prompt-card-featured.png', {
          maxDiffPixels: 100,
        });
        console.log('[VISUAL] PromptCard featured - captured');
      } else {
        console.log('[VISUAL] PromptCard featured - skipped (no featured cards)');
      }
    });
  });

  test.describe('Hero Section', () => {
    test('full hero - light mode', async ({ page }) => {
      await page.goto('/');
      const hero = page.locator('section').first();

      await expect(hero).toHaveScreenshot('hero-light.png', {
        maxDiffPixels: 200,
      });

      console.log('[VISUAL] Hero light mode - captured');
    });

    test('full hero - dark mode', async ({ page }) => {
      await page.goto('/');
      await page.evaluate(() => {
        document.documentElement.classList.add('dark');
      });

      const hero = page.locator('section').first();
      await expect(hero).toHaveScreenshot('hero-dark.png', {
        maxDiffPixels: 200,
      });

      console.log('[VISUAL] Hero dark mode - captured');
    });

    test('category pills - selected state', async ({ page }) => {
      await page.goto('/');

      // Click a category
      await page.click('button:has-text("debugging")');

      const pills = page.locator('[role="group"][aria-label="Filter by category"]');
      await expect(pills).toHaveScreenshot('category-pills-selected.png', {
        maxDiffPixels: 100,
      });

      console.log('[VISUAL] Category pills selected - captured');
    });
  });

  test.describe('SpotlightSearch', () => {
    test('empty state - light mode', async ({ page }) => {
      await page.goto('/');
      await page.keyboard.press('Meta+k');

      await page.waitForSelector('[role="dialog"]');
      const dialog = page.locator('[role="dialog"]');

      await expect(dialog).toHaveScreenshot('spotlight-empty-light.png', {
        maxDiffPixels: 150,
      });

      console.log('[VISUAL] SpotlightSearch empty light - captured');
    });

    test('with results - light mode', async ({ page }) => {
      await page.goto('/');
      await page.keyboard.press('Meta+k');

      await page.fill('input[type="text"]', 'testing');
      await page.waitForTimeout(300); // Debounce

      const dialog = page.locator('[role="dialog"]');
      await expect(dialog).toHaveScreenshot('spotlight-results-light.png', {
        maxDiffPixels: 200,
      });

      console.log('[VISUAL] SpotlightSearch with results - captured');
    });

    test('category selected', async ({ page }) => {
      await page.goto('/');
      await page.keyboard.press('Meta+k');

      await page.click('button:has-text("debugging")');

      const dialog = page.locator('[role="dialog"]');
      await expect(dialog).toHaveScreenshot('spotlight-category-selected.png', {
        maxDiffPixels: 150,
      });

      console.log('[VISUAL] SpotlightSearch category selected - captured');
    });
  });

  test.describe('BasketSidebar', () => {
    test('empty basket', async ({ page }) => {
      await page.goto('/');
      await page.click('[aria-label*="basket"]');

      await page.waitForSelector('aside');
      const sidebar = page.locator('aside');

      await expect(sidebar).toHaveScreenshot('basket-empty.png', {
        maxDiffPixels: 100,
      });

      console.log('[VISUAL] BasketSidebar empty - captured');
    });
  });

  test.describe('PromptDetailModal', () => {
    test('modal open - light mode', async ({ page }) => {
      await page.goto('/');

      // Click view on first card
      await page.click('[data-testid="prompt-card"] button:has-text("View")');

      await page.waitForSelector('[role="dialog"]');
      const modal = page.locator('[role="dialog"]');

      await expect(modal).toHaveScreenshot('prompt-modal-light.png', {
        maxDiffPixels: 300,
      });

      console.log('[VISUAL] PromptDetailModal light - captured');
    });
  });
});
```

### 2. Full Page Screenshots
```typescript
// e2e/visual/pages.spec.ts
import { test, expect } from '@playwright/test';

test.describe('Full Page Visual Regression', () => {

  test('Home page - light mode', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    await expect(page).toHaveScreenshot('home-page-light.png', {
      fullPage: true,
      maxDiffPixels: 500,
    });

    console.log('[VISUAL] Home page light - captured');
  });

  test('Home page - dark mode', async ({ page }) => {
    await page.goto('/');
    await page.evaluate(() => {
      document.documentElement.classList.add('dark');
    });
    await page.waitForLoadState('networkidle');

    await expect(page).toHaveScreenshot('home-page-dark.png', {
      fullPage: true,
      maxDiffPixels: 500,
    });

    console.log('[VISUAL] Home page dark - captured');
  });

  test('Bundles page', async ({ page }) => {
    await page.goto('/bundles');
    await page.waitForLoadState('networkidle');

    await expect(page).toHaveScreenshot('bundles-page.png', {
      fullPage: true,
      maxDiffPixels: 500,
    });

    console.log('[VISUAL] Bundles page - captured');
  });
});
```

### 3. Mobile Viewport Tests
```typescript
// e2e/visual/mobile.spec.ts
import { test, expect, devices } from '@playwright/test';

test.use({ ...devices['iPhone 13'] });

test.describe('Mobile Visual Regression', () => {
  test('Home page - mobile', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    await expect(page).toHaveScreenshot('home-mobile.png', {
      fullPage: true,
      maxDiffPixels: 300,
    });

    console.log('[VISUAL] Home page mobile - captured');
  });

  test('SwipeablePromptCard', async ({ page }) => {
    await page.goto('/');
    const card = page.locator('[data-testid="prompt-card"]').first();

    await expect(card).toHaveScreenshot('swipeable-card-mobile.png', {
      maxDiffPixels: 100,
    });

    console.log('[VISUAL] SwipeablePromptCard mobile - captured');
  });
});
```

## Logging Format
All tests log with consistent format:
```
[VISUAL] {Component} {variant} - {status}
```

Statuses:
- `captured` - Screenshot taken successfully
- `passed` - No visual diff detected
- `failed` - Visual diff detected
- `skipped` - Test skipped (condition not met)

## Failure Output
On failure, Playwright generates:
1. Expected screenshot
2. Actual screenshot
3. Diff screenshot highlighting changes

Test output:
```
[VISUAL] PromptCard light mode default - FAILED
  Expected: baseline/prompt-card-light-default.png
  Actual: test-results/prompt-card-light-default-actual.png
  Diff: test-results/prompt-card-light-default-diff.png

  Difference: 2,547 pixels (5.2%)
  Max allowed: 100 pixels
```

## Baseline Management
```bash
# Update baselines after intentional changes
npx playwright test --update-snapshots

# Update specific test's baseline
npx playwright test visual/components.spec.ts --update-snapshots
```

## CI Integration
```yaml
- name: Visual Regression Tests
  run: |
    echo "=== Running Visual Regression Tests ==="
    npx playwright test e2e/visual/ --reporter=list

- name: Upload Visual Diffs
  if: failure()
  uses: actions/upload-artifact@v4
  with:
    name: visual-diffs
    path: test-results/
```

## Success Criteria
- [ ] All major components have baseline screenshots
- [ ] Light and dark mode coverage
- [ ] Mobile viewport coverage
- [ ] Detailed logging for each test
- [ ] CI integration with artifact upload
- [ ] Baseline update workflow documented

## Files to Create
- e2e/visual/components.spec.ts
- e2e/visual/pages.spec.ts
- e2e/visual/mobile.spec.ts
- e2e/visual/baselines/ (generated)

